# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import Optional

app = FastAPI()

class User(BaseModel):
    email: str
    username: str
    role: str
    account_status: str
    subscription_tier: str

@app.put("/api/users/{user_id}")
async def update_user(user_id: int, user: User, current_user: dict):
    if current_user['role'] != 'admin':
        raise HTTPException(status_code=403, detail="Forbidden")

    # Update user in database
    # For simplicity, assume users are stored as a list
    users = [{'id': 1, 'email': 'user@example.com', 'username': 'john'}, 
             {'id': 2, 'email': 'admin@example.com', 'username': 'admin'}]
    
    for user_dict in users:
        if user_dict['id'] == user_id:
            user_dict['email'] = user.email
            user_dict['username'] = user.username
            user_dict['role'] = user.role
            user_dict['account_status'] = user.account_status
            user_dict['subscription_tier'] = user.subscription_tier

    return {'message': 'User updated successfully'}

